import{_ as c,C as l,o as e,c as m,a4 as o,b as d,w as a,a as s,E as i,a5 as n}from"./chunks/framework.CDpUjPX_.js";const q=JSON.parse('{"title":"Entendendo o Kubex","description":"","frontmatter":{},"headers":[],"relativePath":"guia/entendendo-kubex.md","filePath":"guia/entendendo-kubex.md"}'),u={name:"guia/entendendo-kubex.md"};function h(g,t,b,p,f,A){const r=l("Mermaid");return e(),m("div",null,[t[2]||(t[2]=o('<h1 id="entendendo-o-kubex" tabindex="-1">Entendendo o Kubex <a class="header-anchor" href="#entendendo-o-kubex" aria-label="Permalink to &quot;Entendendo o Kubex&quot;">​</a></h1><p>Guia introdutorio sobre o que e o Kubex, como funciona e como suas pecas se encaixam.</p><hr><h2 id="_1-o-que-e-o-kubex" tabindex="-1">1. O que e o Kubex? <a class="header-anchor" href="#_1-o-que-e-o-kubex" aria-label="Permalink to &quot;1. O que e o Kubex?&quot;">​</a></h2><p>O Kubex e uma <strong>plataforma brasileira de protecao digital</strong>. Funciona como um detetive digital que vigia a internet 24 horas por dia, procurando uso nao autorizado de imagens, videos, rostos e marcas.</p><p>Em termos simples:</p><ul><li>Um fotografo quer saber se alguem esta usando suas fotos sem permissao? O Kubex encontra.</li><li>Uma modelo quer saber se seu rosto aparece em sites indevidos? O Kubex detecta.</li><li>Uma empresa quer proteger sua marca contra pirataria? O Kubex monitora e envia pedidos de remocao.</li></ul><p>O Kubex faz <strong>tres coisas principais</strong>:</p><ol><li><strong>Busca</strong> — Encontra conteudo copiado ou nao autorizado na internet</li><li><strong>Monitora</strong> — Vigia redes sociais, sites e a dark web em tempo real</li><li><strong>Age</strong> — Envia pedidos de remocao (takedowns) automaticamente</li></ol><hr><h2 id="_2-como-o-sistema-funciona" tabindex="-1">2. Como o sistema funciona <a class="header-anchor" href="#_2-como-o-sistema-funciona" aria-label="Permalink to &quot;2. Como o sistema funciona&quot;">​</a></h2>',11)),(e(),d(n,null,{default:a(()=>[i(r,{id:"mermaid-57",class:"mermaid",graph:"%25%25%7Binit%3A%20%7B'theme'%3A%20'dark'%7D%20%7D%25%25%0Agraph%20TD%0A%20%20%20%20A%5B%22Cliente%20acessa%20o%20site%22%5D%20--%3E%20B%5B%22Painel%20do%20Usuario%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22Envia%20imagem%20ou%20nome%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22Backend%20(API)%22%5D%0A%20%20%20%20D%20--%3E%20E%5B%2227%20Motores%20de%20Busca%22%5D%0A%20%20%20%20E%20--%3E%20F%5B%22Vasculham%20a%20internet%22%5D%0A%20%20%20%20F%20--%3E%20G%5B%22Resultados%20voltam%20ao%20painel%22%5D%0A%20%20%20%20G%20--%3E%20H%5B%22Cliente%20pode%20pedir%20remocao%22%5D%0A%0A%20%20%20%20style%20D%20fill%3A%230f172a%2Cstroke%3A%2360a5fa%2Ccolor%3A%23e2e8f0%0A%20%20%20%20style%20E%20fill%3A%230f172a%2Cstroke%3A%2360a5fa%2Ccolor%3A%23e2e8f0%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=o('<h3 id="as-4-camadas" tabindex="-1">As 4 camadas <a class="header-anchor" href="#as-4-camadas" aria-label="Permalink to &quot;As 4 camadas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Camada</th><th>O que faz</th><th>Analogia</th></tr></thead><tbody><tr><td><strong>Frontend</strong></td><td>Site que o cliente acessa para buscas e resultados</td><td>A &quot;vitrine&quot;</td></tr><tr><td><strong>Admin</strong></td><td>Painel de controle do administrador</td><td>O &quot;escritorio&quot;</td></tr><tr><td><strong>Backend (API)</strong></td><td>Cerebro que processa tudo — recebe pedidos, coordena motores, salva dados</td><td>O &quot;gerente&quot;</td></tr><tr><td><strong>Motores</strong></td><td>27 robos especializados que vasculham a internet</td><td>Os &quot;detetives&quot;</td></tr></tbody></table><h3 id="fluxo-de-uma-busca-por-imagem" tabindex="-1">Fluxo de uma busca por imagem <a class="header-anchor" href="#fluxo-de-uma-busca-por-imagem" aria-label="Permalink to &quot;Fluxo de uma busca por imagem&quot;">​</a></h3><ol><li>Cliente faz login e envia uma foto</li><li>Backend cria um &quot;job&quot; e coloca na fila de trabalho</li><li>Motores adequados comecam a trabalhar (Lens, Crawler, Fingerprint, FaceID)</li><li>Resultados voltam ao painel com score de similaridade</li><li>Cliente pode pedir remocao (takedown) dos resultados</li></ol><h3 id="tarefas-automaticas" tabindex="-1">Tarefas automaticas <a class="header-anchor" href="#tarefas-automaticas" aria-label="Permalink to &quot;Tarefas automaticas&quot;">​</a></h3><p>Alem das buscas manuais, o Kubex roda tarefas automaticas continuamente:</p><table tabindex="0"><thead><tr><th>Tarefa</th><th>Frequencia</th></tr></thead><tbody><tr><td>Telegram e Discord</td><td>A cada 10 minutos</td></tr><tr><td>Reddit</td><td>A cada 30 minutos</td></tr><tr><td>Crawler, Google Alerts</td><td>A cada 1 hora</td></tr><tr><td>Twitter/X</td><td>A cada 2 horas</td></tr><tr><td>Instagram</td><td>A cada 3 horas</td></tr><tr><td>BrandWatch (nomes)</td><td>A cada 6 horas</td></tr><tr><td>Facebook</td><td>A cada 6 horas</td></tr><tr><td>Flickr, SourceIntel</td><td>A cada 12 horas</td></tr><tr><td>Lens (re-scan), Dark Web, Limpeza LGPD</td><td>A cada 24 horas</td></tr></tbody></table>',7)),(e(),d(n,null,{default:a(()=>[i(r,{id:"mermaid-244",class:"mermaid",graph:"%25%25%7Binit%3A%20%7B'theme'%3A%20'dark'%7D%20%7D%25%25%0Agraph%20LR%0A%20%20%20%20A%5B%22Celery%20Beat%20agenda%22%5D%20--%3E%20B%5B%22Motor%20executa%20varredura%22%5D%0A%20%20%20%20B%20--%3E%20C%7B%22Encontrou%3F%22%7D%0A%20%20%20%20C%20--%3E%7CSim%7C%20D%5B%22Gera%20alerta%22%5D%0A%20%20%20%20C%20--%3E%7CNao%7C%20E%5B%22Tudo%20limpo%22%5D%0A%20%20%20%20D%20--%3E%20F%5B%22Takedown%20automatico%22%5D%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=o('<hr><h2 id="_3-os-27-motores" tabindex="-1">3. Os 27 Motores <a class="header-anchor" href="#_3-os-27-motores" aria-label="Permalink to &quot;3. Os 27 Motores&quot;">​</a></h2><p>Os motores sao os robos especializados do Kubex, divididos em 8 categorias.</p><blockquote><p>Para detalhes tecnicos de cada motor, veja <a href="./../motores/overview">Motores de Busca</a>.</p></blockquote><h3 id="busca-de-imagens-e-conteudo" tabindex="-1">Busca de Imagens e Conteudo <a class="header-anchor" href="#busca-de-imagens-e-conteudo" aria-label="Permalink to &quot;Busca de Imagens e Conteudo&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Motor</th><th>O que faz</th></tr></thead><tbody><tr><td>1</td><td><strong>Lens</strong></td><td>Busca reversa de imagem via Google Lens (SerpAPI)</td></tr><tr><td>2</td><td><strong>Crawler</strong></td><td>Visita sites de pirataria e baixa paginas para analise. 3 modos: basico, dinamico (JS) e stealth (anti-bot)</td></tr><tr><td>4</td><td><strong>BrandWatch</strong></td><td>Busca por nome/marca com 66+ alvos pre-configurados incluindo Google Dorks brasileiros</td></tr><tr><td>24</td><td><strong>AutoDiscovery</strong></td><td>Descobre automaticamente novos sites e canais piratas via 6 metodos (dork spider, indexadores Telegram, Reddit, cross-reference, manual, ressurreicao)</td></tr></tbody></table><h3 id="analise-e-identificacao" tabindex="-1">Analise e Identificacao <a class="header-anchor" href="#analise-e-identificacao" aria-label="Permalink to &quot;Analise e Identificacao&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Motor</th><th>O que faz</th></tr></thead><tbody><tr><td>3</td><td><strong>Fingerprint</strong></td><td>&quot;Impressao digital&quot; de imagem (pHash/dHash/aHash). Reconhece copias mesmo com alteracoes</td></tr><tr><td>11</td><td><strong>VideoPrint</strong></td><td>Fingerprinting de video via keyframes + pHash</td></tr><tr><td>12</td><td><strong>SemanticAI</strong></td><td>IA (CLIP) que entende o significado da imagem, nao apenas pixels</td></tr><tr><td>20</td><td><strong>OCR</strong></td><td>Le texto dentro de imagens (Tesseract)</td></tr><tr><td>21</td><td><strong>DeepGuard</strong></td><td>Detecta deepfakes com 3 tecnicas combinadas (DCT, Boundary, EfficientNet)</td></tr><tr><td>26</td><td><strong>NSFWGuard</strong></td><td>Classifica conteudo adulto/improprio automaticamente</td></tr></tbody></table><h3 id="reconhecimento-facial" tabindex="-1">Reconhecimento Facial <a class="header-anchor" href="#reconhecimento-facial" aria-label="Permalink to &quot;Reconhecimento Facial&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Motor</th><th>O que faz</th></tr></thead><tbody><tr><td>6</td><td><strong>FaceID</strong></td><td>Reconhecimento facial — selfie gera embedding 512D (InsightFace). Compara com banco de rostos</td></tr><tr><td>23</td><td><strong>Face Index</strong></td><td>Banco de rostos (Milvus HNSW). Indexa faces encontradas na web para busca instantanea</td></tr></tbody></table><blockquote><p>O Kubex NUNCA armazena a selfie original. Gera o mapa matematico e descarta a foto imediatamente.</p></blockquote><h3 id="monitoramento-social" tabindex="-1">Monitoramento Social <a class="header-anchor" href="#monitoramento-social" aria-label="Permalink to &quot;Monitoramento Social&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Motor</th><th>Frequencia</th><th>Plataforma</th></tr></thead><tbody><tr><td>5</td><td><strong>Telegram Monitor</strong></td><td>10 min</td><td>Telegram (MTProto)</td></tr><tr><td>9</td><td><strong>Discord Monitor</strong></td><td>10 min</td><td>Discord (Bot API)</td></tr><tr><td>13</td><td><strong>Reddit Monitor</strong></td><td>30 min</td><td>Reddit (OAuth2 API)</td></tr><tr><td>14</td><td><strong>AlertsFeed</strong></td><td>1 hora</td><td>Google Alerts (RSS)</td></tr><tr><td>15</td><td><strong>X Monitor</strong></td><td>2 horas</td><td>Twitter/X (API v2)</td></tr><tr><td>18</td><td><strong>Instagram Monitor</strong></td><td>3 horas</td><td>Instagram (scraping)</td></tr><tr><td>19</td><td><strong>Marketplace</strong></td><td>24 horas</td><td>ML, OLX, Shopee, Amazon BR</td></tr><tr><td>22</td><td><strong>Facebook</strong></td><td>6 horas</td><td>Facebook (Playwright)</td></tr><tr><td>25</td><td><strong>Flickr</strong></td><td>12 horas</td><td>Flickr (API publica)</td></tr><tr><td>16</td><td><strong>DarkWeb Monitor</strong></td><td>24 horas</td><td>Sites .onion (Tor)</td></tr></tbody></table><h3 id="protecao-inteligencia-e-acoes" tabindex="-1">Protecao, Inteligencia e Acoes <a class="header-anchor" href="#protecao-inteligencia-e-acoes" aria-label="Permalink to &quot;Protecao, Inteligencia e Acoes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Motor</th><th>O que faz</th></tr></thead><tbody><tr><td>10</td><td><strong>Watermark</strong></td><td>Marca d&#39;agua invisivel (DWT-DCT) que identifica quem vazou conteudo</td></tr><tr><td>25</td><td><strong>ShieldAI</strong></td><td>Vasculha sites adultos procurando conteudo nao consentido (NCII)</td></tr><tr><td>17</td><td><strong>SourceIntel</strong></td><td>Descobre e classifica novas fontes de pirataria com scoring de risco</td></tr><tr><td>7</td><td><strong>Takedown</strong></td><td>Takedown automatizado (DMCA / Marco Civil) com auto-escalacao</td></tr><tr><td>8</td><td><strong>Orchestrator</strong></td><td>Orquestra todos os motores via Celery Beat e despacha alertas</td></tr><tr><td>27</td><td><strong>Sentinel</strong></td><td>Watchdog que monitora a saude dos 26 outros motores e tenta recuperar falhas</td></tr></tbody></table><hr><h2 id="_4-painel-admin" tabindex="-1">4. Painel Admin <a class="header-anchor" href="#_4-painel-admin" aria-label="Permalink to &quot;4. Painel Admin&quot;">​</a></h2><p>O Painel Admin (<code>admin.kubex.com.br</code>) permite controlar todo o sistema:</p><table tabindex="0"><thead><tr><th>Secao</th><th>O que faz</th></tr></thead><tbody><tr><td><strong>Dashboard</strong></td><td>KPIs, graficos, saude dos motores</td></tr><tr><td><strong>Usuarios</strong></td><td>Lista, convites, leads, identidades faciais</td></tr><tr><td><strong>Buscas</strong></td><td>Jobs, planos, assinaturas, takedowns</td></tr><tr><td><strong>Monitoramento</strong></td><td>Status dos motores, metricas, health check</td></tr><tr><td><strong>Motores Sociais</strong></td><td>Configuracao de crawlers, targets, canais (Telegram, Discord, Reddit, DarkWeb, etc.)</td></tr><tr><td><strong>Conteudo Avancado</strong></td><td>Watermarks, video hashes, CLIP embeddings</td></tr><tr><td><strong>Inteligencia</strong></td><td>PIB (Piracy Intelligence), deteccao de rings</td></tr><tr><td><strong>Sistema</strong></td><td>Configuracoes, activity logs, audit logs, failed tasks, database</td></tr></tbody></table><hr><h2 id="_5-painel-do-usuario" tabindex="-1">5. Painel do Usuario <a class="header-anchor" href="#_5-painel-do-usuario" aria-label="Permalink to &quot;5. Painel do Usuario&quot;">​</a></h2><p>O que o cliente pode fazer em <code>kubex.com.br</code>:</p><ul><li><strong>Busca por imagem</strong> — envia foto, sistema procura na internet</li><li><strong>Busca por nome</strong> — digita marca/pessoa, sistema busca mencoes (Pro+)</li><li><strong>Busca facial</strong> — envia selfie para encontrar seu rosto na internet (Pro+)</li><li><strong>Takedowns</strong> — solicitar remocao com documento legal automatico</li><li><strong>Monitoramento</strong> — alertas quando novo conteudo pirata e encontrado</li><li><strong>Watermark</strong> — proteger conteudo com marca d&#39;agua invisivel (Pro+)</li><li><strong>Relatorios</strong> — PDF e CSV com evidencias para processos judiciais</li></ul><hr><h2 id="_6-planos-e-precos" tabindex="-1">6. Planos e Precos <a class="header-anchor" href="#_6-planos-e-precos" aria-label="Permalink to &quot;6. Planos e Precos&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Gratuito</th><th>Essencial</th><th>Pro</th></tr></thead><tbody><tr><td><strong>Preco</strong></td><td>R$ 0/mes</td><td>R$ 39/mes</td><td>R$ 89/mes</td></tr><tr><td><strong>Buscas/mes</strong></td><td>5</td><td>50</td><td>Ilimitadas</td></tr><tr><td><strong>Monitoramento</strong></td><td>Nao</td><td>Sim (24h)</td><td>Sim (6h)</td></tr><tr><td><strong>Takedowns</strong></td><td>Nao</td><td>20/mes</td><td>Ilimitados</td></tr><tr><td><strong>Busca facial</strong></td><td>Nao</td><td>Nao</td><td>Sim</td></tr><tr><td><strong>API B2B</strong></td><td>Nao</td><td>Nao</td><td>Sim</td></tr></tbody></table><p>Pagamentos via <strong>Asaas</strong> (PIX, cartao, boleto). Existe tambem o modelo <strong>pay-per-search</strong> (R$ 9,90/busca avulsa).</p><hr><h2 id="_7-takedowns-inteligentes" tabindex="-1">7. Takedowns Inteligentes <a class="header-anchor" href="#_7-takedowns-inteligentes" aria-label="Permalink to &quot;7. Takedowns Inteligentes&quot;">​</a></h2><p>O sistema de takedown funciona com escalacao automatica:</p><ol><li><strong>Envio</strong> — notificacao DMCA ou Marco Civil ao responsavel</li><li><strong>48h</strong> — se nao removeu, reenvia com template mais forte</li><li><strong>7d</strong> — escala para provedor de hospedagem</li><li><strong>14d</strong> — ultimo aviso com linguagem juridica formal</li><li><strong>30d</strong> — recomendacao judicial ao usuario</li></ol><p>Verificacao de remocao usa 3 metodos (HTTP status + analise de conteudo + pHash), com decisao por votacao 2-de-3. Base com 90+ dominios de abuse contacts pre-cadastrados.</p><hr><h2 id="_8-seguranca-e-lgpd" tabindex="-1">8. Seguranca e LGPD <a class="header-anchor" href="#_8-seguranca-e-lgpd" aria-label="Permalink to &quot;8. Seguranca e LGPD&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Medida</th><th>Descricao</th></tr></thead><tbody><tr><td>Senhas</td><td>bcrypt (cost 12), irreversivel</td></tr><tr><td>Auth</td><td>Cookies httpOnly (JWT 15min + refresh 7d)</td></tr><tr><td>2FA</td><td>TOTP (Google Authenticator)</td></tr><tr><td>CPF/CNPJ</td><td>AES-256-GCM + HMAC-SHA256</td></tr><tr><td>CSRF</td><td>Validacao de Origin em requests state-changing</td></tr><tr><td>Rate Limiting</td><td>slowapi + Redis por IP</td></tr><tr><td>Imagens</td><td>NUNCA armazenadas — apenas hashes e thumbnails</td></tr><tr><td>Selfies</td><td>Deletadas imediatamente apos gerar embedding</td></tr><tr><td>Direito ao esquecimento</td><td><code>DELETE /users/me/delete</code> — audit logs anonimizados</td></tr><tr><td>Anti-stalking</td><td>Buscas faciais registram hash + IP, retidos 90 dias</td></tr></tbody></table><hr><h2 id="_9-infraestrutura" tabindex="-1">9. Infraestrutura <a class="header-anchor" href="#_9-infraestrutura" aria-label="Permalink to &quot;9. Infraestrutura&quot;">​</a></h2><p>O Kubex roda em 16 containers Docker organizados em 5 grupos. Para detalhes de cada container, veja <a href="./../arquitetura/docker-services">Servicos Docker</a>.</p><p><strong>Resumo dos grupos:</strong></p><table tabindex="0"><thead><tr><th>Grupo</th><th>Containers</th><th>Funcao</th></tr></thead><tbody><tr><td>Proxy</td><td>nginx</td><td>Reverse proxy, roteamento por dominio</td></tr><tr><td>Sites</td><td>frontend, frontend-admin, docs</td><td>Interfaces web (Next.js, VitePress)</td></tr><tr><td>Cerebro</td><td>api</td><td>FastAPI — logica de negocio</td></tr><tr><td>Workers</td><td>celery-worker, celery-beat, face-worker</td><td>Tarefas async, agendamento, reconhecimento facial</td></tr><tr><td>Dados</td><td>PostgreSQL, Redis Broker, Redis Cache, Milvus, etcd, MinIO</td><td>Armazenamento</td></tr></tbody></table><p><strong>4 bancos de dados, cada um com uma funcao:</strong></p><table tabindex="0"><thead><tr><th>Banco</th><th>Funcao</th></tr></thead><tbody><tr><td><strong>PostgreSQL</strong></td><td>Dados permanentes (usuarios, buscas, pagamentos, audit logs)</td></tr><tr><td><strong>Redis Broker</strong></td><td>Filas Celery, locks, rate limits</td></tr><tr><td><strong>Redis Cache</strong></td><td>Sessoes, cache de queries, thumbnails, job progress</td></tr><tr><td><strong>Milvus</strong></td><td>Embeddings faciais 512D (busca por similaridade)</td></tr></tbody></table><hr><h2 id="_10-numeros-e-capacidade" tabindex="-1">10. Numeros e Capacidade <a class="header-anchor" href="#_10-numeros-e-capacidade" aria-label="Permalink to &quot;10. Numeros e Capacidade&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Operacao</th><th>Velocidade</th></tr></thead><tbody><tr><td>Comparar hash de imagem</td><td>~50ms</td></tr><tr><td>Reconhecer rosto</td><td>~300ms</td></tr><tr><td>Buscar rosto em 100k faces</td><td>~10ms</td></tr><tr><td>OCR em imagem</td><td>~200ms</td></tr><tr><td>Detectar deepfake</td><td>~50-200ms</td></tr><tr><td>Crawl de pagina simples</td><td>~1-3s</td></tr><tr><td>Crawl com anti-bot</td><td>~3-8s</td></tr></tbody></table><p>Em um servidor com 4 CPUs e 8GB RAM, o sistema processa ~5.000 imagens/hora com deteccao facial, suficiente para ~500 usuarios ativos com monitoramento diario.</p>',46))])}const P=c(u,[["render",h]]);export{q as __pageData,P as default};
